#!/usr/bin/env python3
"""Run from repo root to overwrite both files."""
import base64
HTML_B64 = ""
API_B64  = ""
html = base64.b64decode(HTML_B64).decode("utf-8")
api  = base64.b64decode(API_B64).decode("utf-8")
with open("dashboard.html","w",encoding="utf-8") as f: f.write(html)
with open("api.py","w",encoding="utf-8") as f: f.write(api)
print(f"dashboard.html  {len(html):,} chars")
print(f"api.py          {len(api):,} chars")
print("Done! Hard-refresh with Cmd+Shift+R (Mac) or Ctrl+Shift+R (Windows)")
